final:
module RefModule(a, b, sel, y);

    input  [7:0] a;  
    input  [7:0] b;  
    input  sel;
    output  [7:0] y;
  wire [7:0] _tap_a = a & {8{1'b1}};

    reg   [7:0]  y;

    always @(*)
          begin
            if (sel)
                y = b;
            else
                y = a;
          end  

endmodule
